const item = $input.first().json || {};
const staticData = $getWorkflowStaticData('global');

function htmlEscape(text) {
  return String(text || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

function htmlAttr(text) {
  return String(text || '').replace(/&/g, '&amp;').replace(/"/g, '&quot;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

function tgLink(label, url) {
  if (!url) return 'unavailable';
  return '<a href="' + htmlAttr(url) + '">' + htmlEscape(label) + '</a>';
}

function truncateRaw(text, max) {
  var value = String(text || '');
  return value.length <= max ? value : value.slice(0, max - 1) + '\u2026';
}

if (item.error || (typeof item === 'object' && item.error)) {
  var apiErrMsg = item.error?.message || 'n8n API unreachable';
  var apiErrorHash = String(apiErrMsg).slice(0, 300);
  var lastApiErrorHash = staticData.lastApiErrorHash || '';
  var lastApiErrorAt = staticData.lastApiErrorAt || 0;
  var now0 = Date.now();
  var shouldAlertApiError = apiErrorHash !== lastApiErrorHash || (now0 - lastApiErrorAt) > 3600000;
  if (shouldAlertApiError) {
    staticData.lastApiErrorHash = apiErrorHash;
    staticData.lastApiErrorAt = now0;
  }
  staticData.orphanUncertainty = { timestamp: new Date().toISOString(), reason: apiErrMsg };
  return [{
    json: {
      orphanState: 'api_error',
      apiError: true,
      hasOrphans: false,
      hasAlertableOrphans: false,
      shouldAlertOrphans: shouldAlertApiError,
      orphanCount: 0,
      alertableOrphanCount: 0,
      orphanArray: '[]',
      orphanAlertText: shouldAlertApiError
        ? '\ud83d\udd34 <b>HEARTBEAT \u2014 API UNREACHABLE</b>\n\nn8n API at localhost:5678 is not responding.\nOrphan detection may be incomplete this cycle.\n\n<b>Error:</b> <code>' + htmlEscape(truncateRaw(apiErrMsg, 300)) + '</code>\n<b>Timestamp:</b> ' + new Date().toLocaleString('en-PH', { timeZone: 'Asia/Manila', year: 'numeric', month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false })
        : '',
      errorMessage: apiErrMsg
    }
  }];
}

var data = item.data || item;
var arr = Array.isArray(data) ? data : (Array.isArray(data.data) ? data.data : []);

if (!Array.isArray(arr)) {
  staticData.orphanUncertainty = { timestamp: new Date().toISOString(), reason: 'Unexpected n8n API response shape' };
  return [{
    json: {
      orphanState: 'api_error',
      apiError: true,
      hasOrphans: false,
      hasAlertableOrphans: false,
      shouldAlertOrphans: false,
      orphanCount: 0,
      alertableOrphanCount: 0,
      orphanArray: '[]',
      orphanAlertText: '',
      errorMessage: 'Unexpected API response shape'
    }
  }];
}

var healthData = (function() { try { return $('System Status').first().json || {}; } catch(e) { return {}; } })();

if (arr.length === 0) {
  var isActiveSystem = healthData.circuit_status === 'open' || healthData.circuit_status === 'half_open' || !!healthData.error;
  if (isActiveSystem) {
    staticData.orphanUncertainty = { timestamp: new Date().toISOString(), reason: 'API returned 0 running during active system' };
    return [{ json: { orphanState: 'uncertain', apiError: false, hasOrphans: false, hasAlertableOrphans: false, shouldAlertOrphans: false, orphanCount: 0, alertableOrphanCount: 0, orphanArray: '[]', orphanAlertText: '' } }];
  }
  delete staticData.orphanUncertainty;
  return [{ json: { orphanState: 'none', apiError: false, hasOrphans: false, hasAlertableOrphans: false, shouldAlertOrphans: false, orphanCount: 0, alertableOrphanCount: 0, orphanArray: '[]', orphanAlertText: '' } }];
}

var now = Date.now();
var threshold = 30 * 60 * 1000;
var MONITORING_WORKFLOW_IDS = [
  $env.SUPERVISOR_WORKFLOW_ID || '',
  $env.HEARTBEAT_WORKFLOW_ID || '',
  $env.RETENTION_WORKFLOW_ID || ''
].filter(Boolean).map(String);

var LONG_RUNNING_IDS = String($env.LONG_RUNNING_WORKFLOW_IDS || '').split(',').map(function(s) { return s.trim(); }).filter(Boolean);
var excludeIds = new Set([].concat(MONITORING_WORKFLOW_IDS, LONG_RUNNING_IDS));

var baseUrl = $env.N8N_BASE_URL || 'http://localhost:5678';

var orphans = arr.filter(function(exec) {
  var startedAtRaw = exec.startedAt || exec.createdAt;
  var startedAt = new Date(startedAtRaw).getTime();
  if (!startedAt || Number.isNaN(startedAt)) return false;
  return (now - startedAt) > threshold && !excludeIds.has(String(exec.workflowId));
}).map(function(exec) {
  return {
    executionId: String(exec.id),
    workflowId: String(exec.workflowId || 'unknown'),
    workflowName: exec.workflowName || exec.workflow?.name || 'unknown',
    startedAt: exec.startedAt || exec.createdAt,
    runningMinutes: Math.round((now - new Date(exec.startedAt || exec.createdAt).getTime()) / 60000),
    executionUrl: baseUrl + '/executions/' + String(exec.id)
  };
});

var orphanAlertKey = 'orphan_alert_memory';
var orphanMemory = staticData[orphanAlertKey] || {};
var ORPHAN_REALERT_MS = 60 * 60 * 1000;

var alertableOrphans = orphans.filter(function(o) {
  var last = orphanMemory[o.executionId] || 0;
  return (now - last) > ORPHAN_REALERT_MS;
});

for (var ao of alertableOrphans) { orphanMemory[ao.executionId] = now; }
for (var eid of Object.keys(orphanMemory)) {
  if (now - orphanMemory[eid] > 24 * 60 * 60 * 1000) delete orphanMemory[eid];
}
staticData[orphanAlertKey] = orphanMemory;

if (orphans.length === 0) { delete staticData.orphanUncertainty; }

var displayOrphans = alertableOrphans
  .sort(function(a, b) { return b.runningMinutes - a.runningMinutes; })
  .slice(0, 5);
var omittedCount = Math.max(alertableOrphans.length - 5, 0);

var orphanArray = orphans.map(function(o) {
  return { executionId: o.executionId, workflowId: o.workflowId, workflowName: o.workflowName, runningMinutes: o.runningMinutes, orphanCount: orphans.length };
});

var orphanAlertText = '';
if (displayOrphans.length > 0) {
  orphanAlertText = '\u26a0\ufe0f <b>ORPHAN EXECUTION DETECTED</b>\n\n';
  orphanAlertText += displayOrphans.map(function(o) {
    return '<b>Execution:</b> ' + tgLink('#' + o.executionId, o.executionUrl) + '\n<b>Workflow:</b> ' + htmlEscape(truncateRaw(o.workflowName, 100)) + '\n<b>Running:</b> ' + o.runningMinutes + ' minutes';
  }).join('\n---\n');
  if (omittedCount > 0) { orphanAlertText += '\n\n\u2026and ' + omittedCount + ' more orphan(s) omitted.'; }
  orphanAlertText += '\n\n<b>Total Orphans:</b> ' + alertableOrphans.length;
  orphanAlertText += '\n<b>Timestamp:</b> ' + new Date().toLocaleString('en-PH', { timeZone: 'Asia/Manila', year: 'numeric', month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false });
}

return [{
  json: {
    orphanState: orphans.length > 0 ? 'found' : 'none',
    apiError: false,
    hasOrphans: orphans.length > 0,
    hasAlertableOrphans: alertableOrphans.length > 0,
    shouldAlertOrphans: alertableOrphans.length > 0,
    orphanCount: orphans.length,
    alertableOrphanCount: alertableOrphans.length,
    orphanArray: JSON.stringify(orphanArray),
    orphanAlertText: orphanAlertText
  }
}];

const crypto = require('crypto');
const item = $input.first().json || {};
const staticData = $getWorkflowStaticData('global');

function htmlEscape(text) {
  return String(text || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

function htmlAttr(text) {
  return String(text || '').replace(/&/g, '&amp;').replace(/"/g, '&quot;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

function tgLink(label, url) {
  if (!url) return 'unavailable';
  return '<a href="' + htmlAttr(url) + '">' + htmlEscape(label) + '</a>';
}

function truncateRaw(text, max) {
  var value = String(text || '');
  return value.length <= max ? value : value.slice(0, max - 1) + '\u2026';
}

function formatTimestamp() {
  return new Date().toLocaleString('en-PH', {
    timeZone: 'Asia/Manila', year: 'numeric', month: 'short', day: 'numeric',
    hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false
  });
}

var expectedIds = String($env.CRITICAL_WORKFLOW_IDS || '').split(',').map(function(s) { return s.trim(); }).filter(Boolean);
var baseUrl = $env.N8N_BASE_URL || 'http://localhost:5678';

if (expectedIds.length === 0) {
  delete staticData.activationCheckUncertain;
  var noConfigHash = crypto.createHash('sha1').update(JSON.stringify({ activationIssue: false, activationUncertain: false, deactivatedIds: [] })).digest('hex');
  staticData.lastActivationStateHash = noConfigHash;
  return [{ json: { activationConfigured: false, activationIssue: false, hasDeactivated: false, activationUncertain: false, shouldAlertActivation: false, deactivatedIds: [], deactivatedUrls: [], activeCount: 0, expectedCount: 0, activationMessage: 'CRITICAL_WORKFLOW_IDS not configured', activationAlertText: '', activationDisplayText: '' } }];
}

if (item.error && item.error.message) {
  staticData.activationCheckUncertain = { timestamp: new Date().toISOString(), reason: item.error.message };
  var h1 = crypto.createHash('sha1').update(JSON.stringify({ activationIssue: true, activationUncertain: true, deactivatedIds: [] })).digest('hex');
  var changed1 = h1 !== (staticData.lastActivationStateHash || '');
  staticData.lastActivationStateHash = h1;
  var alertText1 = changed1
    ? '\u26a0\ufe0f <b>WORKFLOW ACTIVATION CHECK</b>\n\nActivation check is uncertain. No workflow is being declared inactive from this result.\n\n<b>Status:</b> ' + htmlEscape(item.error.message) + '\n<b>Expected Critical:</b> ' + expectedIds.length + '\n<b>Active Returned:</b> 0\n\n<b>Timestamp:</b> ' + formatTimestamp()
    : '';
  return [{ json: { activationConfigured: true, activationIssue: true, hasDeactivated: false, activationUncertain: true, shouldAlertActivation: changed1, deactivatedIds: [], deactivatedUrls: [], activeCount: 0, expectedCount: expectedIds.length, activationMessage: item.error.message, activationAlertText: alertText1, activationDisplayText: '\u26a0\ufe0f <b>Activation Uncertain:</b> ' + htmlEscape(truncateRaw(item.error.message, 200)) } }];
}

var data = item.data || item;
var arr = Array.isArray(data) ? data : (Array.isArray(data.data) ? data.data : []);

if (!Array.isArray(arr)) {
  staticData.activationCheckUncertain = { timestamp: new Date().toISOString(), reason: 'Unexpected response shape' };
  var hShape = crypto.createHash('sha1').update(JSON.stringify({ activationIssue: true, activationUncertain: true, deactivatedIds: [] })).digest('hex');
  staticData.lastActivationStateHash = hShape;
  return [{ json: { activationConfigured: true, activationIssue: true, hasDeactivated: false, activationUncertain: true, shouldAlertActivation: false, deactivatedIds: [], deactivatedUrls: [], activeCount: 0, expectedCount: expectedIds.length, activationMessage: 'Unexpected response shape', activationAlertText: '', activationDisplayText: '\u26a0\ufe0f <b>Activation Uncertain:</b> Unexpected response shape' } }];
}

var activeIds = new Set(arr.map(function(w) { return String(w.id); }));
var deactivatedIds = expectedIds.filter(function(id) { return !activeIds.has(String(id)); });
var deactivatedUrls = deactivatedIds.map(function(id) { return baseUrl + '/workflow/' + id; });

var activationIssue = deactivatedIds.length > 0;
var activationMessage = activationIssue ? deactivatedIds.length + ' critical workflow(s) inactive' : 'All critical workflows active';

var stateHash = crypto.createHash('sha1').update(JSON.stringify({ activationIssue: activationIssue, activationUncertain: false, deactivatedIds: deactivatedIds.sort() })).digest('hex');
var lastHash = staticData.lastActivationStateHash || '';
var activationChanged = stateHash !== lastHash;

// G: Always update state hash (not just on issue)
staticData.lastActivationStateHash = stateHash;

delete staticData.activationCheckUncertain;

// B2+: Pre-build activation alert text
var activationAlertText = '';
if (activationIssue && activationChanged) {
  var linkLines = deactivatedUrls.map(function(u, i) {
    return '\u2022 ' + tgLink('Workflow ' + deactivatedIds[i], u);
  }).join('\n');
  activationAlertText = '\u26a0\ufe0f <b>WORKFLOW ACTIVATION CHECK</b>\n\nOne or more critical workflows appear inactive.\n\n<b>Status:</b> ' + activationMessage + '\n<b>Expected Critical:</b> ' + expectedIds.length + '\n<b>Active Returned:</b> ' + activeIds.size + '\n<b>Inactive:</b>\n' + linkLines + '\n\n<b>Timestamp:</b> ' + formatTimestamp();
}

// B2+: Pre-build display text for heartbeat dashboard
var activationDisplayText = '';
if (activationIssue) {
  var displayLinks = deactivatedUrls.map(function(u, i) {
    return tgLink('WF ' + deactivatedIds[i], u);
  }).join(', ');
  activationDisplayText = '\u26a0\ufe0f <b>Inactive Critical:</b> ' + displayLinks;
} else {
  activationDisplayText = '\u2705 <b>Workflows:</b> ' + expectedIds.length + '/' + expectedIds.length + ' active';
}

return [{ json: { activationConfigured: true, activationIssue: activationIssue, hasDeactivated: deactivatedIds.length > 0, activationUncertain: false, shouldAlertActivation: activationIssue && activationChanged, deactivatedIds: deactivatedIds, deactivatedUrls: deactivatedUrls, activeCount: activeIds.size, expectedCount: expectedIds.length, activationMessage: activationMessage, activationAlertText: activationAlertText, activationDisplayText: activationDisplayText } }];

const crypto = require('crypto');

function htmlEscape(text) {
  return String(text || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

function truncateRaw(text, max) {
  var value = String(text || '');
  return value.length <= max ? value : value.slice(0, max - 1) + '\u2026';
}

// B3: Tag-safe clampTelegramHtml with mandatory stack-based tag closer
function clampTelegramHtml(value, max) {
  max = max || 3900;
  var s = String(value || '');
  if (s.length <= max) return s;
  var note = '\n\n\u26a0\ufe0f <i>Message truncated</i>';
  var cutPoint = max - note.length;
  var lastOpenBracket = s.lastIndexOf('<', cutPoint);
  var lastCloseBracket = s.lastIndexOf('>', cutPoint);
  if (lastOpenBracket > lastCloseBracket) {
    cutPoint = lastOpenBracket;
  }
  var truncated = s.substring(0, cutPoint);
  var openTags = [];
  var tagRegex = /<(\/?)([a-z]+)\b[^>]*>/gi;
  var match;
  while ((match = tagRegex.exec(truncated)) !== null) {
    if (match[1] === '/') { openTags.pop(); }
    else { openTags.push(match[2]); }
  }
  for (var ti = openTags.length - 1; ti >= 0; ti--) {
    truncated += '</' + openTags[ti] + '>';
  }
  return truncated + note;
}

function formatTimestamp() {
  return new Date().toLocaleString('en-PH', {
    timeZone: 'Asia/Manila', year: 'numeric', month: 'short', day: 'numeric',
    hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false
  });
}

var statusItem = (function() { try { return $('System Status').first().json || {}; } catch(e) { return {}; } })();
var activationItem = (function() { try { return $('Detect Activation State').first().json || {}; } catch(e) { return {}; } })();
var orphanItem = (function() { try { return $('Detect Orphans').first().json || {}; } catch(e) { return {}; } })();
var staticData = $getWorkflowStaticData('global');

var isDbError = !!(statusItem.error && typeof statusItem.error === 'object' && statusItem.error.message);
var cs = isDbError ? 'unknown' : (statusItem.circuit_status || 'unknown');
var ec = isDbError ? 0 : (parseInt(statusItem.error_count, 10) || 0);
var errHour = isDbError ? 0 : (parseInt(statusItem.errors_last_hour, 10) || 0);
var err24h = isDbError ? 0 : (parseInt(statusItem.errors_last_24h, 10) || 0);
var retries1h = isDbError ? 0 : (parseInt(statusItem.retries_last_hour, 10) || 0);
var retries24h = isDbError ? 0 : (parseInt(statusItem.retries_last_24h, 10) || 0);

var hasOrphans = orphanItem.hasOrphans || false;
var orphanCount = orphanItem.orphanCount || 0;
var orphanState = orphanItem.orphanState || 'unknown';

var topSources = [];
try {
  var raw = statusItem.top_error_sources;
  if (typeof raw === 'string') topSources = JSON.parse(raw);
  else if (Array.isArray(raw)) topSources = raw;
} catch(e) { topSources = []; }

var circuitIcon = cs === 'closed' ? '\ud83d\udfe2' : cs === 'half_open' ? '\ud83d\udfe1' : cs === 'open' ? '\ud83d\udd34' : '\u26aa';

var prevHourErrors = staticData.prevCycleErrorsHour || 0;
var direction = errHour > prevHourErrors ? '\ud83d\udcc8' : errHour < prevHourErrors ? '\ud83d\udcc9' : '\u27a1\ufe0f';
staticData.prevCycleErrorsHour = errHour;

var trend = errHour >= 3 ? '\ud83d\udd34 spike ' + direction : err24h >= 10 ? '\ud83d\udfe1 elevated ' + direction : '\ud83d\udfe2 stable';

var cachedCount = (staticData.eventFailures && staticData.eventFailures.length) || 0;
var droppedCount = staticData.droppedCacheCount || 0;

var emergencyNote = '';
if (cachedCount > 0) {
  emergencyNote = '\n\ud83d\udea8 <b>Heartbeat Local Cache:</b> ' + cachedCount + ' failed event(s)';
  if (droppedCount > 0) emergencyNote += ' (' + droppedCount + ' dropped due to overflow)';
}

var dmsNote = '';
if (staticData.lastDeadMansSwitchFailure) {
  dmsNote = '\n\u26a0\ufe0f <b>DMS Failure:</b> <code>' + htmlEscape(truncateRaw(String(staticData.lastDeadMansSwitchFailure), 200)) + '</code>';
}

var orphanIcon = orphanState === 'found' ? '\ud83d\udd34' : orphanState === 'uncertain' ? '\ud83d\udfe1' : orphanState === 'api_error' ? '\ud83d\udd34' : orphanState === 'none' ? '\ud83d\udfe2' : '\u26aa';
var orphanText = orphanState === 'found' ? orphanCount + ' detected' : orphanState === 'uncertain' ? 'uncertain' : orphanState === 'api_error' ? 'API unreachable' : orphanState === 'none' ? 'none' : 'unknown';

// B2+: Use pre-built activationDisplayText
var activationNote = '';
if (activationItem.activationUncertain) {
  activationNote = '\n' + (activationItem.activationDisplayText || '\u26a0\ufe0f <b>Activation Uncertain</b>');
} else if (activationItem.hasDeactivated) {
  activationNote = '\n' + (activationItem.activationDisplayText || '\u26a0\ufe0f <b>Inactive Critical Workflows</b>');
} else if (activationItem.activationConfigured) {
  activationNote = '\n' + (activationItem.activationDisplayText || '\u2705 <b>Workflows:</b> active');
}

var dbNote = isDbError ? '\n\ud83d\udd34 <b>DATABASE UNREACHABLE</b>' : '';

var isDegraded = isDbError || cs === 'open' || cs === 'half_open' || cachedCount > 0 || !!staticData.lastDeadMansSwitchFailure || orphanState === 'uncertain' || orphanState === 'api_error' || !!activationItem.activationUncertain || !!activationItem.hasDeactivated || hasOrphans;
var isCritical = isDbError || cs === 'open';
var currentVerdict = isCritical ? 'CRITICAL' : isDegraded ? 'DEGRADED' : 'HEALTHY';
var verdict = isCritical ? '\ud83d\udd34 CRITICAL' : isDegraded ? '\ud83d\udfe1 DEGRADED' : '\ud83d\udfe2 HEALTHY';

var previousVerdict = staticData.lastVerdict || 'HEALTHY';
var isRecovery = previousVerdict !== 'HEALTHY' && currentVerdict === 'HEALTHY';

var recoveryDetails = [];
if (isRecovery && staticData.lastDegradedReasons) {
  var prev = staticData.lastDegradedReasons;
  if (prev.circuitOpen && cs === 'closed') recoveryDetails.push('circuit closed');
  if (prev.dmsFailure && !staticData.lastDeadMansSwitchFailure) recoveryDetails.push('DMS restored');
  if (prev.activationIssue && !activationItem.activationIssue) recoveryDetails.push('workflows reactivated');
  if (prev.dbError && !isDbError) recoveryDetails.push('database reconnected');
  if (prev.cachedFailures && cachedCount === 0) recoveryDetails.push('cache cleared');
  if (prev.hasOrphans && !hasOrphans) recoveryDetails.push('orphans resolved');
}

if (isDegraded) {
  staticData.lastDegradedReasons = { circuitOpen: cs === 'open', dmsFailure: !!staticData.lastDeadMansSwitchFailure, activationIssue: !!activationItem.activationIssue, dbError: isDbError, cachedFailures: cachedCount > 0, hasOrphans: hasOrphans };
} else {
  delete staticData.lastDegradedReasons;
}
staticData.lastVerdict = currentVerdict;

var topSourcesLine = '';
if (topSources.length > 0) {
  topSourcesLine = '\n\n\ud83c\udfc6 <b>Top Sources (24h):</b>';
  topSources.forEach(function(src, i) {
    topSourcesLine += '\n' + (i + 1) + '. ' + htmlEscape(truncateRaw(src.workflow_name, 60)) + ' \u2014 ' + src.error_count + ' errors' + (src.errors_1h > 0 ? ' (' + src.errors_1h + ' in 1h)' : '');
  });
}

var recoveryBanner = isRecovery
  ? '\u2705 <b>RECOVERED</b> \u2014 System returned to HEALTHY from ' + previousVerdict + (recoveryDetails.length > 0 ? ' (' + recoveryDetails.join(', ') + ')' : '') + '\n\n'
  : '';

var text = recoveryBanner + '\ud83d\udc93 <b>SUPERVISOR \u2014 ' + verdict + '</b>\n\n'
  + circuitIcon + ' <b>Circuit:</b> ' + cs + ' (' + ec + '/5)\n'
  + (staticData.lastDeadMansSwitchFailure ? '\ud83d\udd34' : '\ud83d\udfe2') + ' <b>DMS:</b> ' + (staticData.lastDeadMansSwitchFailure ? 'FAILED' : 'ok') + '\n'
  + (activationItem.activationConfigured ? (activationItem.activationIssue ? '\ud83d\udd34' : '\ud83d\udfe2') + ' <b>Workflows:</b> ' + (activationItem.activationIssue ? activationItem.activationMessage : activationItem.expectedCount + '/' + activationItem.expectedCount + ' active') : '\u26aa <b>Workflows:</b> not configured') + '\n'
  + orphanIcon + ' <b>Orphans:</b> ' + orphanText + '\n'
  + '\ud83d\udcca <b>Trend:</b> ' + trend + '\n'
  + '\ud83d\udd04 <b>Auto-Retries:</b> ' + retries1h + ' (1h) \u00b7 ' + retries24h + ' (24h)\n'
  + '\n<b>Errors:</b> ' + errHour + ' (1h) \u00b7 ' + err24h + ' (24h)'
  + topSourcesLine
  + dbNote + emergencyNote + dmsNote + activationNote
  + '\n\n<b>Timestamp:</b> ' + formatTimestamp();

text = clampTelegramHtml(text);

// Hash for dedup — stable bucketing
var stableErrHour = Math.floor(errHour / 3) * 3;
var stableErr24h = Math.floor(err24h / 5) * 5;
var stableTopSources = topSources.map(function(s) { return s.workflow_name + ':' + (Math.floor(s.error_count / 3) * 3); }).join(',');

var hashInput = cs + ':' + ec + ':' + stableErrHour + ':' + stableErr24h + ':' + isDbError + ':' + cachedCount + ':' + droppedCount + ':' + !!staticData.lastDeadMansSwitchFailure + ':' + orphanState + ':' + orphanCount + ':' + !!activationItem.activationUncertain + ':' + !!activationItem.hasDeactivated + ':' + (activationItem.deactivatedIds?.join(',') || '') + ':' + stableTopSources + ':' + retries1h + ':' + retries24h;
var messageHash = crypto.createHash('md5').update(hashInput).digest('hex');
var lastSentHash = staticData.lastHeartbeatHash || '';
var isDuplicate = messageHash === lastSentHash;

// L3: Time-elapsed hourly pulse (drift-resilient)
var now = Date.now();
var lastHealthyPulseAt = staticData.lastHealthyPulseAt || 0;
var pulseIntervalMs = 55 * 60 * 1000; // 55 minutes

var shouldSend = false;
var sendReason = 'suppressed';

if (isDbError) { shouldSend = true; sendReason = 'database_unreachable'; }
else if (isRecovery) { shouldSend = true; sendReason = 'recovery_to_healthy'; }
else if (isDegraded && !isDuplicate) { shouldSend = true; sendReason = 'degraded_state_changed'; }
else if (!isDegraded && (now - lastHealthyPulseAt) >= pulseIntervalMs) { shouldSend = true; sendReason = 'hourly_healthy_pulse'; }

return [{
  json: {
    text: text,
    messageHash: messageHash,
    isDuplicate: isDuplicate,
    isDegraded: isDegraded,
    isCritical: isCritical,
    verdict: verdict,
    shouldSend: shouldSend,
    sendReason: sendReason,
    dbError: isDbError,
    circuit_status: cs,
    error_count: ec,
    errors_last_hour: errHour,
    errors_last_24h: err24h,
    retries_last_hour: retries1h,
    retries_last_24h: retries24h,
    emergency_cache_count: cachedCount,
    dropped_cache_count: droppedCount,
    dms_failure_active: !!staticData.lastDeadMansSwitchFailure,
    orphan_state: orphanState,
    orphan_count: orphanCount,
    activation_uncertain: !!activationItem.activationUncertain,
    activation_issue: !!activationItem.activationIssue,
    activation_deactivated_ids: activationItem.deactivatedIds || []
  }
}];

var staticData = $getWorkflowStaticData('global');
var evalData = (function() { try { return $('Evaluate System Health').first().json; } catch(e) { return {}; } })();

staticData.lastHeartbeatHash = evalData.messageHash || '';

// L3: Update lastHealthyPulseAt when healthy pulse sent
if (!evalData.isDegraded && evalData.shouldSend) {
  staticData.lastHealthyPulseAt = Date.now();
}

staticData.eventFailures = [];
staticData.droppedCacheCount = 0;
staticData.lastSuccessfulHeartbeatAt = new Date().toISOString();

return [{ json: { cacheCleared: true, hashUpdated: true } }];

var item = $input.first().json || {};
var staticData = $getWorkflowStaticData('global');
var isError = !!(item.error && typeof item.error === 'object' && item.error.message);
if (isError) {
  staticData.lastDeadMansSwitchFailure = item.error.message;
} else {
  delete staticData.lastDeadMansSwitchFailure;
}
return [{ json: { dmsFailure: isError, dmsOk: !isError, dmsErrorMessage: isError ? item.error.message : '' } }];

var staticData = $getWorkflowStaticData('global');
var item = $input.first().json || {};
if (!staticData.eventFailures) staticData.eventFailures = [];
staticData.eventFailures.push({
  timestamp: new Date().toISOString(),
  traceId: item.traceId || 'unknown',
  eventType: 'alert_failed',
  source: 'Heartbeat Monitor',
  workflowName: 'Heartbeat Monitor',
  failedNode: item.failedNode || 'unknown',
  reason: item.error?.message || 'Telegram or Postgres delivery failed — cached in Heartbeat local cache'
});
if (staticData.eventFailures.length > 50) {
  staticData.droppedCacheCount = (staticData.droppedCacheCount || 0) + (staticData.eventFailures.length - 50);
  staticData.eventFailures = staticData.eventFailures.slice(-50);
}
return [{ json: { cached: true, count: staticData.eventFailures.length } }];
